SELECT category_name 
FROM vehicle_categories 
ORDER BY category_name ASC;

SELECT AVG(weekly_equivalent) AS average_weekly_equivalent
FROM leasing_terms
WHERE down_payment > 5000;

SELECT COUNT(*) AS user_count
FROM users
WHERE status = 'active';

SELECT AVG(notification_count) AS average_notifications
FROM (
    SELECT user_id, COUNT(notification_id) AS notification_count
    FROM notifications
    GROUP BY user_id
);

SELECT vehicle_id, mileage, 
       PERCENT_RANK() OVER (ORDER BY mileage) AS percentage_rank 
FROM vehicles;

SELECT make, model
FROM (
  SELECT make, model, ROW_NUMBER() OVER (ORDER BY msrp DESC) AS row_num
  FROM vehicles
) AS ranked_vehicles
WHERE row_num <= 5;

SELECT ROUND(AVG(msrp), 2) AS AverageMSRP
FROM vehicles
WHERE availability = 'available';

SELECT lh.leasing_history_id, lh.vehicle_id, lh.start_date, lh.end_date, lh.total_mileage, lh.condition, lh.return_date
FROM leasing_history lh
WHERE lh.leasing_term_id = 1;
